import{_ as a}from"./plugin-vue_export-helper.21dcd24c.js";import{d as P}from"./app.30963f6b.js";const p={},i=P('<h1 id="udp\u548Ctcp" tabindex="-1"><a class="header-anchor" href="#udp\u548Ctcp" aria-hidden="true">#</a> UDP\u548CTCP</h1><h3 id="_2-udp-\u628A\u6570\u636E\u5305\u9001\u8FBE\u5E94\u7528\u7A0B\u5E8F" tabindex="-1"><a class="header-anchor" href="#_2-udp-\u628A\u6570\u636E\u5305\u9001\u8FBE\u5E94\u7528\u7A0B\u5E8F" aria-hidden="true">#</a> 2. UDP\uFF1A\u628A\u6570\u636E\u5305\u9001\u8FBE\u5E94\u7528\u7A0B\u5E8F</h3><p>IP\u662F\u975E\u5E38\u5E95\u5C42\u7684\u534F\u8BAE\uFF0C\u53EA\u8D1F\u8D23\u628A\u6570\u636E\u5305\u4F20\u9001\u5230\u5BF9\u65B9\u7535\u8111\uFF0C\u4F46\u662F\u5BF9\u65B9\u7535\u8111\u5E76\u4E0D\u77E5\u9053\u628A\u6570\u636E\u5305\u4EA4\u7ED9\u54EA\u4E2A\u7A0B\u5E8F\uFF0C\u662F\u4EA4\u7ED9\u6D4F\u89C8\u5668\u8FD8\u662F\u4EA4\u7ED9\u738B\u8005\u8363\u8000\uFF1F\u56E0\u6B64\uFF0C\u9700\u8981\u57FA\u4E8EIP\u4E4B\u4E0A\u5F00\u53D1\u80FD\u548C\u5E94\u7528\u6253\u4EA4\u9053\u7684\u534F\u8BAE\uFF0C\u6700\u5E38\u89C1\u7684\u662F\u201C\u7528\u6237\u6570\u636E\u5305\u534F\u8BAE\uFF08User Datagram Protocol\uFF09\u201D\uFF0C\u7B80\u79F0UDP\u3002</p><p>UDP\u4E2D\u4E00\u4E2A\u6700\u91CD\u8981\u7684\u4FE1\u606F\u662F\u7AEF\u53E3\u53F7\uFF0C\u7AEF\u53E3\u53F7\u5176\u5B9E\u5C31\u662F\u4E00\u4E2A\u6570\u5B57\uFF0C\u6BCF\u4E2A\u60F3\u8BBF\u95EE\u7F51\u7EDC\u7684\u7A0B\u5E8F\u90FD\u9700\u8981\u7ED1\u5B9A\u4E00\u4E2A\u7AEF\u53E3\u53F7\u3002\u901A\u8FC7\u7AEF\u53E3\u53F7UDP\u5C31\u80FD\u628A\u6307\u5B9A\u7684\u6570\u636E\u5305\u53D1\u9001\u7ED9\u6307\u5B9A\u7684\u7A0B\u5E8F\u4E86\uFF0C\u6240\u4EE5IP\u901A\u8FC7IP\u5730\u5740\u4FE1\u606F\u628A\u6570\u636E\u5305\u53D1\u9001\u7ED9\u6307\u5B9A\u7684\u7535\u8111\uFF0C\u800CUDP\u901A\u8FC7\u7AEF\u53E3\u53F7\u628A\u6570\u636E\u5305\u5206\u53D1\u7ED9\u6B63\u786E\u7684\u7A0B\u5E8F\u3002\u548CIP\u5934\u4E00\u6837\uFF0C\u7AEF\u53E3\u53F7\u4F1A\u88AB\u88C5\u8FDBUDP\u5934\u91CC\u9762\uFF0CUDP\u5934\u518D\u548C\u539F\u59CB\u6570\u636E\u5305\u5408\u5E76\u7EC4\u6210\u65B0\u7684UDP\u6570\u636E\u5305\u3002UDP\u5934\u4E2D\u9664\u4E86\u76EE\u7684\u7AEF\u53E3\uFF0C\u8FD8\u6709\u6E90\u7AEF\u53E3\u53F7\u7B49\u4FE1\u606F</p><p>\u4E3A\u4E86\u652F\u6301UDP\u534F\u8BAE\uFF0C\u6211\u628A\u524D\u9762\u7684\u4E09\u5C42\u7ED3\u6784\u6269\u5145\u4E3A\u56DB\u5C42\u7ED3\u6784\uFF0C\u5728\u7F51\u7EDC\u5C42\u548C\u4E0A\u5C42\u4E4B\u95F4\u589E\u52A0\u4E86\u4F20\u8F93\u5C42\uFF0C\u5982\u4E0B\u56FE\u6240\u793A\uFF1A</p><p><img src="https://mc-web-1259409954.cos.ap-guangzhou.myqcloud.com/MyImages/3edb673a43f23d84253c52124ce447ea.png" alt=""></p><p>\u4E0B\u9762\u6211\u4EEC\u4E00\u8D77\u6765\u770B\u4E0B\u4E00\u4E2A\u6570\u636E\u5305\u4ECE\u4E3B\u673AA\u65C5\u884C\u5230\u4E3B\u673AB\u7684\u8DEF\u7EBF\uFF1A</p><ul><li>\u4E0A\u5C42\u5C06\u542B\u6709\u201C\u6781\u5BA2\u65F6\u95F4\u201D\u7684\u6570\u636E\u5305\u4EA4\u7ED9\u4F20\u8F93\u5C42\uFF1B</li><li>\u4F20\u8F93\u5C42\u4F1A\u5728\u6570\u636E\u5305\u524D\u9762\u9644\u52A0\u4E0AUDP\u5934\uFF0C\u7EC4\u6210\u65B0\u7684UDP\u6570\u636E\u5305\uFF0C\u518D\u5C06\u65B0\u7684UDP\u6570\u636E\u5305\u4EA4\u7ED9\u7F51\u7EDC\u5C42\uFF1B</li><li>\u7F51\u7EDC\u5C42\u518D\u5C06IP\u5934\u9644\u52A0\u5230\u6570\u636E\u5305\u4E0A\uFF0C\u7EC4\u6210\u65B0\u7684IP\u6570\u636E\u5305\uFF0C\u5E76\u4EA4\u7ED9\u5E95\u5C42\uFF1B</li><li>\u6570\u636E\u5305\u88AB\u4F20\u8F93\u5230\u4E3B\u673AB\u7684\u7F51\u7EDC\u5C42\uFF0C\u5728\u8FD9\u91CC\u4E3B\u673AB\u62C6\u5F00IP\u5934\u4FE1\u606F\uFF0C\u5E76\u5C06\u62C6\u5F00\u6765\u7684\u6570\u636E\u90E8\u5206\u4EA4\u7ED9\u4F20\u8F93\u5C42\uFF1B</li><li>\u5728\u4F20\u8F93\u5C42\uFF0C\u6570\u636E\u5305\u4E2D\u7684UDP\u5934\u4F1A\u88AB\u62C6\u5F00\uFF0C\u5E76\u6839\u636EUDP\u4E2D\u6240\u63D0\u4F9B\u7684\u7AEF\u53E3\u53F7\uFF0C\u628A\u6570\u636E\u90E8\u5206\u4EA4\u7ED9\u4E0A\u5C42\u7684\u5E94\u7528\u7A0B\u5E8F\uFF1B</li><li>\u6700\u7EC8\uFF0C\u542B\u6709\u201C\u6781\u5BA2\u65F6\u95F4\u201D\u4FE1\u606F\u7684\u6570\u636E\u5305\u5C31\u65C5\u884C\u5230\u4E86\u4E3B\u673AB\u4E0A\u5C42\u5E94\u7528\u7A0B\u5E8F\u8FD9\u91CC</li></ul><p>\u5728\u4F7F\u7528UDP\u53D1\u9001\u6570\u636E\u65F6\uFF0C\u6709\u5404\u79CD\u56E0\u7D20\u4F1A\u5BFC\u81F4\u6570\u636E\u5305\u51FA\u9519\uFF0C\u867D\u7136UDP\u53EF\u4EE5\u6821\u9A8C\u6570\u636E\u662F\u5426\u6B63\u786E\uFF0C\u4F46\u662F\u5BF9\u4E8E\u9519\u8BEF\u7684\u6570\u636E\u5305\uFF0CUDP\u5E76\u4E0D\u63D0\u4F9B\u91CD\u53D1\u673A\u5236\uFF0C\u53EA\u662F\u4E22\u5F03\u5F53\u524D\u7684\u5305\uFF0C\u800C\u4E14UDP\u5728\u53D1\u9001\u4E4B\u540E\u4E5F\u65E0\u6CD5\u77E5\u9053\u662F\u5426\u80FD\u8FBE\u5230\u76EE\u7684\u5730\u3002</p><p>\u867D\u8BF4UDP\u4E0D\u80FD\u4FDD\u8BC1\u6570\u636E\u53EF\u9760\u6027\uFF0C\u4F46\u662F\u4F20\u8F93\u901F\u5EA6\u5374\u975E\u5E38\u5FEB\uFF0C\u6240\u4EE5UDP\u4F1A\u5E94\u7528\u5728\u4E00\u4E9B\u5173\u6CE8\u901F\u5EA6\u3001\u4F46\u4E0D\u90A3\u4E48\u4E25\u683C\u8981\u6C42\u6570\u636E\u5B8C\u6574\u6027\u7684\u9886\u57DF\uFF0C\u5982\u5728\u7EBF\u89C6\u9891\u3001\u4E92\u52A8\u6E38\u620F\u7B49</p><h3 id="_3-tcp-\u628A\u6570\u636E\u5B8C\u6574\u5730\u9001\u8FBE\u5E94\u7528\u7A0B\u5E8F" tabindex="-1"><a class="header-anchor" href="#_3-tcp-\u628A\u6570\u636E\u5B8C\u6574\u5730\u9001\u8FBE\u5E94\u7528\u7A0B\u5E8F" aria-hidden="true">#</a> 3. TCP\uFF1A\u628A\u6570\u636E\u5B8C\u6574\u5730\u9001\u8FBE\u5E94\u7528\u7A0B\u5E8F</h3><p>\u5BF9\u4E8E\u6D4F\u89C8\u5668\u8BF7\u6C42\uFF0C\u6216\u8005\u90AE\u4EF6\u8FD9\u7C7B\u8981\u6C42\u6570\u636E\u4F20\u8F93\u53EF\u9760\u6027\uFF08reliability\uFF09\u7684\u5E94\u7528\uFF0C\u5982\u679C\u4F7F\u7528UDP\u6765\u4F20\u8F93\u4F1A\u5B58\u5728\u4E24\u4E2A\u95EE\u9898\uFF1A</p><ul><li>\u6570\u636E\u5305\u5728\u4F20\u8F93\u8FC7\u7A0B\u4E2D\u5BB9\u6613\u4E22\u5931\uFF1B</li><li>\u5927\u6587\u4EF6\u4F1A\u88AB\u62C6\u5206\u6210\u5F88\u591A\u5C0F\u7684\u6570\u636E\u5305\u6765\u4F20\u8F93\uFF0C\u8FD9\u4E9B\u5C0F\u7684\u6570\u636E\u5305\u4F1A\u7ECF\u8FC7\u4E0D\u540C\u7684\u8DEF\u7531\uFF0C\u5E76\u5728\u4E0D\u540C\u7684\u65F6\u95F4\u5230\u8FBE\u63A5\u6536\u7AEF\uFF0C\u800CUDP\u534F\u8BAE\u5E76\u4E0D\u77E5\u9053\u5982\u4F55\u7EC4\u88C5\u8FD9\u4E9B\u6570\u636E\u5305\uFF0C\u4ECE\u800C\u628A\u8FD9\u4E9B\u6570\u636E\u5305\u8FD8\u539F\u6210\u5B8C\u6574\u7684\u6587\u4EF6</li></ul><p>\u57FA\u4E8E\u8FD9\u4E24\u4E2A\u95EE\u9898\uFF0C\u6211\u4EEC\u5F15\u5165TCP\u4E86\u3002TCP\uFF08Transmission Control Protocol\uFF0C\u4F20\u8F93\u63A7\u5236\u534F\u8BAE\uFF09\u662F\u4E00\u79CD\u9762\u5411\u8FDE\u63A5\u7684\u3001\u53EF\u9760\u7684\u3001\u57FA\u4E8E\u5B57\u8282\u6D41\u7684\u4F20\u8F93\u5C42\u901A\u4FE1\u534F\u8BAE\u3002\u76F8\u5BF9\u4E8EUDP\uFF0CTCP\u6709\u4E0B\u9762\u4E24\u4E2A\u7279\u70B9:</p><ul><li>\u5BF9\u4E8E\u6570\u636E\u5305\u4E22\u5931\u7684\u60C5\u51B5\uFF0CTCP\u63D0\u4F9B\u91CD\u4F20\u673A\u5236\uFF1B</li><li>TCP\u5F15\u5165\u4E86\u6570\u636E\u5305\u6392\u5E8F\u673A\u5236\uFF0C\u7528\u6765\u4FDD\u8BC1\u628A\u4E71\u5E8F\u7684\u6570\u636E\u5305\u7EC4\u5408\u6210\u4E00\u4E2A\u5B8C\u6574\u7684\u6587\u4EF6\u3002</li></ul><p>\u548CUDP\u5934\u4E00\u6837\uFF0CTCP\u5934\u9664\u4E86\u5305\u542B\u4E86\u76EE\u6807\u7AEF\u53E3\u548C\u672C\u673A\u7AEF\u53E3\u53F7\u5916\uFF0C\u8FD8\u63D0\u4F9B\u4E86\u7528\u4E8E\u6392\u5E8F\u7684\u5E8F\u5217\u53F7\uFF0C\u4EE5\u4FBF\u63A5\u6536\u7AEF\u901A\u8FC7\u5E8F\u53F7\u6765\u91CD\u6392\u6570\u636E\u5305\u3002</p><p>\u4E0B\u9762\u770B\u770BTCP\u4E0B\u7684\u5355\u4E2A\u6570\u636E\u5305\u7684\u4F20\u8F93\u6D41\u7A0B</p><p><img src="https://mc-web-1259409954.cos.ap-guangzhou.myqcloud.com/MyImages/943ac29f7d5b45a8861b0cde5da99032.png" alt=""></p><p>\u901A\u8FC7\u4E0A\u56FE\u4F60\u5E94\u8BE5\u53EF\u4EE5\u4E86\u89E3\u4E00\u4E2A\u6570\u636E\u5305\u662F\u5982\u4F55\u901A\u8FC7TCP\u6765\u4F20\u8F93\u7684\u3002TCP\u5355\u4E2A\u6570\u636E\u5305\u7684\u4F20\u8F93\u6D41\u7A0B\u548CUDP\u6D41\u7A0B\u5DEE\u4E0D\u591A\uFF0C\u4E0D\u540C\u7684\u5730\u65B9\u5728\u4E8E\uFF0C\u901A\u8FC7TCP\u5934\u7684\u4FE1\u606F\u4FDD\u8BC1\u4E86\u4E00\u5757\u5927\u7684\u6570\u636E\u4F20\u8F93\u7684\u5B8C\u6574\u6027\u3002</p><p>\u4E0B\u9762\u6211\u4EEC\u518D\u770B\u4E0B\u5B8C\u6574\u7684TCP\u8FDE\u63A5\u8FC7\u7A0B\uFF0C\u901A\u8FC7\u8FD9\u4E2A\u8FC7\u7A0B\u4F60\u53EF\u4EE5\u660E\u767DTCP\u662F\u5982\u4F55\u4FDD\u8BC1\u91CD\u4F20\u673A\u5236\u548C\u6570\u636E\u5305\u7684\u6392\u5E8F\u529F\u80FD\u7684\u3002</p><p>\u4ECE\u4E0B\u56FE\u53EF\u4EE5\u770B\u51FA\uFF0C\u4E00\u4E2A\u5B8C\u6574\u7684TCP\u8FDE\u63A5\u7684\u751F\u547D\u5468\u671F\u5305\u62EC\u4E86\u201C\u5EFA\u7ACB\u8FDE\u63A5\u201D\u201C\u4F20\u8F93\u6570\u636E\u201D\u548C\u201C\u65AD\u5F00\u8FDE\u63A5\u201D\u4E09\u4E2A\u9636\u6BB5\u3002</p><p><img src="https://mc-web-1259409954.cos.ap-guangzhou.myqcloud.com/MyImages/440ee50de56edc27c6b3c992b3a25844.png" alt=""></p><ul><li><strong>\u9996\u5148\uFF0C\u5EFA\u7ACB\u8FDE\u63A5\u9636\u6BB5</strong>\u3002\u8FD9\u4E2A\u9636\u6BB5\u662F\u901A\u8FC7\u201C\u4E09\u6B21\u63E1\u624B\u201D\u6765\u5EFA\u7ACB\u5BA2\u6237\u7AEF\u548C\u670D\u52A1\u5668\u4E4B\u95F4\u7684\u8FDE\u63A5\u3002TCP \u63D0\u4F9B\u9762\u5411\u8FDE\u63A5\u7684\u901A\u4FE1\u4F20\u8F93\u3002\u9762\u5411\u8FDE\u63A5\u662F\u6307\u5728\u6570\u636E\u901A\u4FE1\u5F00\u59CB\u4E4B\u524D\u5148\u505A\u597D\u4E24\u7AEF\u4E4B\u95F4\u7684\u51C6\u5907\u5DE5\u4F5C\u3002\u6240\u8C13\u4E09\u6B21\u63E1\u624B\uFF0C\u662F\u6307\u5728\u5EFA\u7ACB\u4E00\u4E2ATCP\u8FDE\u63A5\u65F6\uFF0C\u5BA2\u6237\u7AEF\u548C\u670D\u52A1\u5668\u603B\u5171\u8981\u53D1\u9001\u4E09\u4E2A\u6570\u636E\u5305\u4EE5\u786E\u8BA4\u8FDE\u63A5\u7684\u5EFA\u7ACB\u3002</li><li><strong>\u5176\u6B21\uFF0C\u4F20\u8F93\u6570\u636E\u9636\u6BB5</strong>\u3002\u5728\u8BE5\u9636\u6BB5\uFF0C\u63A5\u6536\u7AEF\u9700\u8981\u5BF9\u6BCF\u4E2A\u6570\u636E\u5305\u8FDB\u884C\u786E\u8BA4\u64CD\u4F5C\uFF0C\u4E5F\u5C31\u662F\u63A5\u6536\u7AEF\u5728\u63A5\u6536\u5230\u6570\u636E\u5305\u4E4B\u540E\uFF0C\u9700\u8981\u53D1\u9001\u786E\u8BA4\u6570\u636E\u5305\u7ED9\u53D1\u9001\u7AEF\u3002\u6240\u4EE5\u5F53\u53D1\u9001\u7AEF\u53D1\u9001\u4E86\u4E00\u4E2A\u6570\u636E\u5305\u4E4B\u540E\uFF0C\u5728\u89C4\u5B9A\u65F6\u95F4\u5185\u6CA1\u6709\u63A5\u6536\u5230\u63A5\u6536\u7AEF\u53CD\u9988\u7684\u786E\u8BA4\u6D88\u606F\uFF0C\u5219\u5224\u65AD\u4E3A\u6570\u636E\u5305\u4E22\u5931\uFF0C\u5E76\u89E6\u53D1\u53D1\u9001\u7AEF\u7684\u91CD\u53D1\u673A\u5236\u3002\u540C\u6837\uFF0C\u4E00\u4E2A\u5927\u7684\u6587\u4EF6\u5728\u4F20\u8F93\u8FC7\u7A0B\u4E2D\u4F1A\u88AB\u62C6\u5206\u6210\u5F88\u591A\u5C0F\u7684\u6570\u636E\u5305\uFF0C\u8FD9\u4E9B\u6570\u636E\u5305\u5230\u8FBE\u63A5\u6536\u7AEF\u540E\uFF0C\u63A5\u6536\u7AEF\u4F1A\u6309\u7167TCP\u5934\u4E2D\u7684\u5E8F\u53F7\u4E3A\u5176\u6392\u5E8F\uFF0C\u4ECE\u800C\u4FDD\u8BC1\u7EC4\u6210\u5B8C\u6574\u7684\u6570\u636E\u3002</li><li><strong>\u6700\u540E\uFF0C\u65AD\u5F00\u8FDE\u63A5\u9636\u6BB5</strong>\u3002\u6570\u636E\u4F20\u8F93\u5B8C\u6BD5\u4E4B\u540E\uFF0C\u5C31\u8981\u7EC8\u6B62\u8FDE\u63A5\u4E86\uFF0C\u6D89\u53CA\u5230\u6700\u540E\u4E00\u4E2A\u9636\u6BB5\u201C\u56DB\u6B21\u6325\u624B\u201D\u6765\u4FDD\u8BC1\u53CC\u65B9\u90FD\u80FD\u65AD\u5F00\u8FDE\u63A5</li></ul><p>\u5230\u8FD9\u91CC\u4F60\u5E94\u8BE5\u5C31\u660E\u767D\u4E86\uFF0CTCP\u4E3A\u4E86\u4FDD\u8BC1\u6570\u636E\u4F20\u8F93\u7684\u53EF\u9760\u6027\uFF0C\u727A\u7272\u4E86\u6570\u636E\u5305\u7684\u4F20\u8F93\u901F\u5EA6\uFF0C\u56E0\u4E3A\u201C\u4E09\u6B21\u63E1\u624B\u201D\u548C\u201C\u6570\u636E\u5305\u6821\u9A8C\u673A\u5236\u201D\u7B49\u628A\u4F20\u8F93\u8FC7\u7A0B\u4E2D\u7684\u6570\u636E\u5305\u7684\u6570\u91CF\u63D0\u9AD8\u4E86\u4E00\u500D\u3002</p>',24);function l(e,t){return i}var o=a(p,[["render",l],["__file","L2.html.vue"]]);export{o as default};
